SELECT MAX(consumption_rate) AS highest_consumption_rate
FROM material_usage
WHERE year = 2022;

SELECT material_id, SUM(quantity) AS total_quantity_used
FROM material_usage
WHERE material_id = 1;

SELECT material_name, cost_per_unit * 100 AS total_cost_for_hundred_units
FROM materials
ORDER BY total_cost_for_hundred_units DESC;
